recepcionesChange(){
  let hacer= 'si'
  let nuevosChange = {}
  switch (hacer) {
  case 'si':
    const nuevos = this._publicos.crearArreglo2(this.recepciones)
    nuevos.forEach(element => {
      
      // console.log(element['servicios']);
      // if (element['servicios']) {
        const servicios = element['servicios']
        servicios.map(e=>{
          if (e['aprobado']) {
            e['showStatus'] = 'Aprobado'
          }
           if (!e['aprobado']) {
            e['showStatus'] = 'No aprobado'
          } 
          if (e['terminado']) {
            e['showStatus'] = 'Terminado'
          }
        })
        console.log(servicios);
      // }
      nuevosChange[element['id']] = element
    });
    console.log(nuevosChange);
    const updates = {};
    updates[`recepciones`] = nuevosChange;
    update(ref(db), updates).then(()=>{
      console.log('termino de remplazar');
    });
    break;

  default:
    break;
}
  
}

