  registraEmpresas(){
    let  value = 0
    const sucursal = '-N2glF34lV3Gj0bQyEWK'
    switch (value) {
      case 0:
        console.log('no hacer nada');
        break;
      case 1:
        let info = {}
        this.empresas.map((e,i)=>{
          const newPostKey = push(child(ref(db), 'posts')).key
          info[newPostKey] = {empresa: e}
        })
        set(ref(db, `empresas/${sucursal}`), info )
          .then(() => {
            // Data saved successfully!
            this._publicos.mensajeCorrecto('termino registro')
          })
          .catch((error) => {
            // The write failed...
          });
        break;
      case 2:
        get(child(dbRef, `empresas/${sucursal}`)).then((snapshot) => {
          if (snapshot.exists()) {
            const arreglo = this._publicos.crearArreglo2(snapshot.val())
            console.log(arreglo);
            
          } else {
            console.log("No data available");
          }
        }).catch((error) => {
          console.error(error);
        });
        break;
      default:
        break;
    }
  }
